	ELSE
		IF (:FIRST_MEIOSH_SYNTAKSHS_TEAM IS NOT NULL AND :FIRST_MEIOSH_SYNTAKSHS_TEAM!='0') THEN
			V_DISPLAY:='ΜΕΙΩΜΕΝΗ';
		ELSIF (:FIRST_MEIOSH_SYNTAKSHS_TEAM IS NULL AND :FIRST_MEIOSH_TEAM_200 IS NOT NULL AND :FIRST_MEIOSH_TEAM_200!='0' ) THEN
			V_DISPLAY:='ΜΕΙΩΜΕΝΗ';
		ELSE
			V_DISPLAY:='ΠΛΗΡΗ';
		END IF;
	END IF;
	
	IF :QUALIFYING_SUBTERM_CODE2 IN ('650','657') THEN
		V_DISPLAY:='ΠΛΗΡΗ';
	END IF;
	RETURN V_DISPLAY;
end;

