      function CF_KATHGORIA_YPALLILOY return Char is
 v_title_code VARCHAR2(5); 
 v_value VARCHAR2(50);
 v_descr VARCHAR2(150);
begin
  
  v_title_code := '00031'; 
	v_value:=  (FIND_FACT_SUB_DEATH_VARCHAR(:p_insured_id,
					                            :p_dt_decision_year,
					                            :p_dt_dec_unit_code,
								                      :P_DEC_INCR_SEC_NO_SR,
								                      '1',
								                      0,
									                    :P_FORM_ID,
									                    '00001',
									                    v_title_code,
									                    '00046'));
/*	IF v_value IS NOT NULL THEN
     v_descr := v_value;	    
	END IF;*/
	
	RETURN 	v_value;
	
	EXCEPTION
  	WHEN NO_DATA_FOUND THEN
