      function CF_NUMBER_OF_DAYSFormula return Char is

DAYS   NUMBER;
mychar  VARCHAR2(50);

Cursor cur_days IS
SELECT A.NUMBER_OF_DAYS
FROM PEN_ACCOUNT A
WHERE A.ACCOUNT_NO =:P_ACC_ACCOUNT_NO;

begin
	OPEN cur_days;
	FETCH cur_days
	into days;
  CLOSE cur_days;
  
  IF TRUNC(MOD(DAYS,300)/25)!=0 THEN
  mychar :=TRUNC(days/300) ||' ETH ΚΑΙ ' ||TRUNC(MOD(DAYS,300)/25) || ' ΜΗΝΕΣ';
  ELSE
  mychar :=TRUNC(days/300);
  
  END IF;
 
  return mychar;
  
end;

