      function CF_33FORMULA0052 return Number is
V_AMOUNT NUMBER;
V_BONUS	NUMBER;


CURSOR CUR_FIND IS
SELECT PEN_ACCOUNT.SECURED_AMOUNT_FOR_REIN,
				greatest(PEN_ACCOUNT.HEAVY_BONUS_IND,pen_account.heavy_bonus_org) 
  FROM  PEN_ACCOUNT
WHERE PEN_ACCOUNT.ACCOUNT_NO= :P_ACC_ACCOUNT_NO;


BEGIN
OPEN  CUR_FIND;
FETCH CUR_FIND
INTO  V_AMOUNT,
			V_BONUS;
CLOSE CUR_FIND;

	IF NVL(V_BONUS,0)>0 THEN
		:CP_1 := ' (Έχει συμπεριληφθεί το Επίδομα '||V_BONUS||')';
	END IF;
	
	RETURN V_AMOUNT;
	


end;

