      Function CF_44Formula return Number is
V_Disab_Cause VARCHAR2(10);    
V_PERC        NUMBER;

CURSOR CUR_V_PERC IS
SELECT   PEN_NPDD_DISABILITY_DATA.Disability_Prcn_Per_Capt
FROM     PEN_NPDD_DISABILITY_DATA
WHERE    PEN_NPDD_DISABILITY_DATA.Disability_Type  = V_Disab_Cause
AND      :CF_39 BETWEEN PEN_NPDD_DISABILITY_DATA.Disability_Prcn_From AND PEN_NPDD_DISABILITY_DATA.Disability_Prcn_To
AND      PEN_NPDD_DISABILITY_DATA.Product_Per_Institution_Code = :P_PRODINST;

CURSOR CUR_PEN_ACCOUNT_CAPTAIN_PRCN IS
SELECT PRCN
FROM  PEN_ACCOUNT_CAPTAIN_PRCN
WHERE ACCOUNT = :P_ACC_ACCOUNT_NO;
  
BEGIN
  V_Disab_Cause    := Find_Fact_Sub_Death_Varchar(  :P_Insured_Id,
                                                 :P_DT_DECISION_YEAR,
                                                 :P_DT_DEC_UNIT_CODE,
                                                 :P_DEC_INCR_SEC_NO_SR,
                                                 '1',
                                                                  0,
                                                                   :P_FORM_ID,
                                                 '00001',
                                                 '00056',
                                                 '00071');
  
OPEN CUR_PEN_ACCOUNT_CAPTAIN_PRCN;
FETCH CUR_PEN_ACCOUNT_CAPTAIN_PRCN
INTO V_PERC;
CLOSE CUR_PEN_ACCOUNT_CAPTAIN_PRCN; 

IF V_PERC IS NULL THEN
	OPEN CUR_V_PERC;
	FETCH CUR_V_PERC
	INTO V_PERC;
	CLOSE CUR_V_PERC;
END IF;


RETURN V_PERC; 


END;

