      function CF_51Formula return Date is

V_DATE	DATE;
V_WAGE_SCALE	NUMBER;

CURSOR CUR_WAGE_SCALE1 IS
SELECT  WAGE_SCALE
FROM PEN_AVERAGE_WAGE_PER_INS_2008
WHERE INS_INSURED_ID = :P_INSURED_ID
AND DT_START > TO_DATE('01/01/2008','DD/MM/RRRR')
ORDER BY DT_START DESC;


CURSOR CUR_WAGE_SCALE2 IS
SELECT DT_START
FROM PEN_AVERAGE_WAGE_PER_INS_2008
WHERE INS_INSURED_ID = :P_INSURED_ID
AND DT_START > TO_DATE('01/01/2008','DD/MM/RRRR')
ORDER BY DT_START DESC;


begin
  
  OPEN CUR_WAGE_SCALE1;
  FETCH CUR_WAGE_SCALE1
  INTO 	 V_WAGE_SCALE;
  CLOSE CUR_WAGE_SCALE1;
  
  IF V_WAGE_SCALE IS NOT NULL THEN
  
  V_DATE:=FIND_FACT_SUB_DEATH_VARCHAR(:P_INSURED_ID ,
					                            :p_dt_decision_year,
					                            :p_dt_dec_unit_code,
								                      :P_DEC_INCR_SEC_NO_SR,
								                      '1',
								                      0,
									                    :P_FORM_ID,
									                    '00001',
									                    '00031',
									                    '00777');
  
  IF V_DATE IS NULL THEN 
  	
  OPEN CUR_WAGE_SCALE2;
  FETCH CUR_WAGE_SCALE2
  INTO 	 V_DATE;
  CLOSE CUR_WAGE_SCALE2;
  	
  END IF;
  
  
  
  
  
  	RETURN V_DATE;
  
  
  
  
  
  
  
  
  ELSE
		RETURN NULL;
  END IF;
  
end;

      function CF_MIN_MAX_DATESFormula return Char is
begin
  
  DECLARE
  	
  	CURSOR DATES IS 
  	SELECT MIN(DT_START),MAX(DT_END) 
		FROM PEN_AVERAGE_WAGE_PER_INS_2008 FF 
		WHERE FF.INS_INSURED_ID=:P_INSURED_ID;
		
		
		MY_DT_START DATE;
		MY_DT_END		DATE;

BEGIN		
		
		IF NVL(:TOTAL_AMOUNT_2008,0) != '0' THEN
		
		
		
		
		OPEN DATES;
		FETCH DATES
		INTO MY_DT_START,MY_DT_END;
		CLOSE DATES;
		
		RETURN 'ΑΠΟ '||''||MY_DT_START||' ΕΩΣ '||MY_DT_END;
		
		ELSE
		
		RETURN '';
		
		END IF;
			
  END;
  
  
end;

