      function CF_53Formula return Date is
v_DATE DATE;
 

Cursor cur_Psv_user_id is 
SELECT A.COMMIT_DATE
FROM PEN_DECISION_INSTANCE A
WHERE A.DT_DOCUMENT_TYPE_DEC_CODE='1'
AND   A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE
AND   A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR
AND   A.DEC_INCR_SEQ_NO=:P_Dec_Incr_Sec_No;


begin
   --Psv_User_Id    := Sec_Appl_Pkg.Get_Current_User(:P_Login_Id);
   
       OPEN cur_Psv_user_id;
      FETCH cur_Psv_user_id
      INTO v_DATE;
      CLOSE cur_Psv_user_id;

 
   RETURN v_DATE; 
end;

